import React from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/navigation";
import "swiper/css/pagination";
import "./ProductsDetails.css";
import { EffectFade, Navigation, Pagination, Autoplay } from "swiper/modules";
import { useParams } from "react-router-dom";
function ProductsDetails({ images }) {
  const { ProductId } = useParams();

  return (
    <>
      <Swiper
        rewind={true}
        spaceBetween={30}
        effect={"fade"}
        navigation={true}
        autoplay={{
          delay: 2500,
        }}
        pagination={{
          clickable: true,
          type: "bullets",
        }}
        modules={[EffectFade, Navigation, Pagination, Autoplay]}
        className="mySwiper"
      >
        {images[ProductId].Images.map((image, index) => {
          return (
            <SwiperSlide key={index}>
              <img src={image.image}></img>
            </SwiperSlide>
          );
        })}
      </Swiper>
      <section className="products-details-section ">
        <h1>{images[ProductId].title}</h1>
        <p className="products-details-text-title">Product Description</p>
        <p className="products-details-text-info">
          {images[ProductId].description}
        </p>
        <p className="products-details-text-title">Product ingredients</p>
        <p className="products-details-text-info">
          {images[ProductId].ingredients}
        </p>
        <p className="products-details-text-title">Weight</p>
        <p className="products-details-text-info">{images[ProductId].weight}</p>
        <p className="products-details-text-title">Packing</p>
        <p className="products-details-text-info">
          {images[ProductId].packing}
        </p>
      </section>
    </>
  );
}

export default ProductsDetails;
